        Processed       = $processed
        Failed          = $failed
        Retried         = $retried
        DeadLetterCount = Get-QueueCount -Queue $deadLetterQueue
        DeadLetterQueue = $deadLetterQueue
        Results         = $results
        Summary         = $summary
    }
}

